class Solution:
    def findWinners(self, matches):
        players = set()
        losses = {}
        for w, l in matches:
            players.add(w)
            players.add(l)
            losses[l] = losses.get(l, 0) + 1
        zero = sorted(p for p in players if losses.get(p, 0) == 0)
        one = sorted(p for p in players if losses.get(p, 0) == 1)
        return [zero, one]

