class Solution:
    def findWinners(self, matches):
        loss_count = {}
        for winner, loser in matches:
            loss_count.setdefault(winner, 0)
            loss_count[loser] = loss_count.get(loser, 0) + 1
        zero_losses = sorted(p for p, c in loss_count.items() if c == 0)
        one_loss = sorted(p for p, c in loss_count.items() if c == 1)
        return [zero_losses, one_loss]

