var findWinners = function(matches) {
    const lossCount = new Map();
    for (const [winner, loser] of matches) {
        if (!lossCount.has(winner)) lossCount.set(winner, 0);
        lossCount.set(loser, (lossCount.get(loser) || 0) + 1);
    }
    const zero = [];
    const one = [];
    for (const [player, count] of lossCount.entries()) {
        if (count === 0) zero.push(player);
        else if (count === 1) one.push(player);
    }
    zero.sort((a, b) => a - b);
    one.sort((a, b) => a - b);
    return [zero, one];
};
